cpp
// Start from end to ensure swaps only affect previously processed memory
for (int i = list.size() - 1; i >= 0; --i) {
if (list[i].marked_for_deletion()) {
swap_and_pop(list, i);
}
}

cpp
for (int i = 0; i < list.size(); ) {
if (list[i].marked_for_deletion()) {
swap_and_pop(list, i);
// Index i now holds the new element from the tail; do NOT increment.
} else {
i++; // Only move forward if no mutation occurred
}
}
